import React, { createContext, useContext, useState, useEffect } from "react";
import { jwtDecode } from "jwt-decode";

const UserContext = createContext();

export function UserProvider({ children }) {
  const [user, setUser] = useState(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check token on app load
    checkToken();

    // Listen for login and logout events
    window.addEventListener("login", checkToken);
    window.addEventListener("logout", handleLogoutEvent);

    return () => {
      window.removeEventListener("login", checkToken);
      window.removeEventListener("logout", handleLogoutEvent);
    };
  }, []);

  const checkToken = () => {
    const token = localStorage.getItem("token");

    if (token) {
      try {
        const decoded = jwtDecode(token);
        setUser({
          userId: decoded.sub || decoded.userId || decoded.id, // JWT standard uses 'sub' for subject
          username: decoded.username || decoded.preferred_username,
          authToken: token
        });
        setIsLoggedIn(true);
      } catch (error) {
        console.error("Failed to decode token:", error);
        localStorage.removeItem("token");
        setUser(null);
        setIsLoggedIn(false);
      }
    } else {
      setUser(null);
      setIsLoggedIn(false);
    }
    setLoading(false);
  };

  const handleLogoutEvent = () => {
    setUser(null);
    setIsLoggedIn(false);
  };

  const login = (token) => {
    localStorage.setItem("token", token);
    checkToken();
  };

  const logout = () => {
    localStorage.removeItem("token");
    window.dispatchEvent(new Event("logout"));
    setUser(null);
    setIsLoggedIn(false);
  };

  return (
    <UserContext.Provider
      value={{
        user,
        isLoggedIn,
        loading,
        userId: user?.userId,
        username: user?.username,
        login,
        logout
      }}
    >
      {children}
    </UserContext.Provider>
  );
}

export function useUser() {
  const context = useContext(UserContext);

  if (!context) {
    throw new Error("useUser must be used within a UserProvider");
  }

  return context;
}
